def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        for j in range(1, 21):
            threshold = j * 0.05
            if ratio <= threshold:
                weight = (21 - j) ** 1.5
                log_term = np.log(j + 2)
                trig_term = np.cos(ratio * np.pi * j) + np.sin(ratio * np.pi * (j / 2))
                score += weight * log_term * trig_term
            else:
                penalty = j * (ratio ** 1.2) * (1 + (j % 4) * 0.15)
                if j % 2 == 0:
                    penalty *= 1.1
                else:
                    penalty *= 0.9
                score -= penalty
            if j % 5 == 0:
                if ratio < 0.5:
                    score += np.exp(-ratio * j) * 0.3
                else:
                    score -= np.sqrt(j) * (ratio - 0.5) * 0.4
        if capacity % 4 == 0:
            score *= 1.25
            for k in range(1, 6):
                div = capacity // k
                if div % 2 == 0:
                    score += np.log(k + 2) * (ratio ** 2) * 0.6
                else:
                    score -= np.sqrt(k + 2) * (1 - ratio) ** 1.5 * 0.5
                if div % 3 == 0:
                    score += np.sin(div * ratio * np.pi / 3) * 0.4
                else:
                    score -= np.cos(div * ratio * np.pi / 4) * 0.3
        else:
            score *= 0.75
            for m in range(7):
                angle = ratio * np.pi * (m + 1)
                if m % 2 == 0:
                    score += np.sin(angle) * 0.25
                else:
                    score -= np.cos(angle) * 0.15
                if m == 3 or m == 5:
                    score += np.tan(angle / 4) * 0.1 if abs(np.tan(angle / 4)) < 10 else 0
        if score < 0:
            score = 0
        if capacity > 50:
            score *= 1.1
            for n in range(3):
                score += np.log1p(capacity) * (0.05 * (n + 1)) * np.sin(ratio * np.pi * (n + 2))
        else:
            score *= 0.9
            for p in range(2):
                score -= np.sqrt(capacity) * 0.02 * (p + 1) * np.cos(ratio * np.pi * (p + 3))
        priorities[i] = score
    return priorities
